1	type Item = { type: string; material: string; enchantment: number; cursed: boolean };
2	type Step = { op: string; items: Item[] };
3	type Result = { premium: number };
4	type ScenarioInput = { customer: { yearsWithMHPCO: number }; steps: Step[] };
5	type ScenarioOutput = { results: Result[] };
6	
7	const BASE_PREMIUMS: Record<string, number> = {
8	  sword: 100,
9	  amulet: 60,
10	  staff: 80,
11	  potion: 40,
12	};
13	
14	const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
15	const CURSED_SURCHARGE_PERCENT = 50;
16	const HIGH_ENCHANTMENT_SURCHARGE_PERCENT = 30;
17	const HIGH_ENCHANTMENT_THRESHOLD = 5;
18	const PROCESSING_FEE = 5;
19	
20	const addSurchargePercent = (amount: number, percent: number): number =>
21	  (amount * (100 + percent)) / 100;
22	
23	const addSurchargeIf = (amount: number, condition: boolean, percent: number): number =>
24	  condition ? addSurchargePercent(amount, percent) : amount;
25	
26	const itemPremium = (item: Item): number => {
27	  const base = BASE_PREMIUMS[item.type];
28	  const withCursed = addSurchargeIf(base, item.cursed, CURSED_SURCHARGE_PERCENT);
29	  return addSurchargeIf(
30	    withCursed,
31	    item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD,
32	    HIGH_ENCHANTMENT_SURCHARGE_PERCENT,
33	  );
34	};
35	
36	const sumItemPremiums = (items: Item[]): number =>
37	  items.reduce((sum, item) => sum + itemPremium(item), 0);
38	
39	const quotePremium = (items: Item[], yearsWithMHPCO: number): number => {
40	  const withFirstInsurance = addSurchargePercent(
41	    sumItemPremiums(items),
42	    FIRST_INSURANCE_SURCHARGE_PERCENT,
43	  );
44	  const withLoyalty = yearsWithMHPCO >= 2 ? (withFirstInsurance * 80) / 100 : withFirstInsurance;
45	  return withLoyalty + PROCESSING_FEE;
46	};
47	
48	export const runScenario = (input: ScenarioInput): ScenarioOutput => ({
49	  results: input.steps.map((step) => ({
50	    premium: quotePremium(step.items, input.customer.yearsWithMHPCO),
51	  })),
52	});
